from matplotlib import pyplot as pltimport numpy as npimport cv2img = cv2.imread("../data/f16.jpg")#image as BGRimg_gray = cv2.cvtColor(img, cv2.COLOR_BGR2GRAY)template_img = cv2.imread("../data/f16_template.jpg",0)#image as grayh,w = template_img.shaperes = cv2.matchTemplate(img_gray, template_img, cv2.TM_CCOEFF_NORMED)#methods available: ['cv2.TM_CCOEFF', 'cv2.TM_CCOEFF_NORMED', 'cv2.TM_CCORR',#            'cv2.TM_CCORR_NORMED', 'cv2.TM_SQDIFF', 'cv2.TM_SQDIFF_NORMED']threshold = 0.6loc = np.where(res>=threshold)#(array([10, 30, 50]), y coordinate# array([20, 40, 60])) x coordinatefor pt in zip(*loc[::-1]):#-1 reverses the coordinate from yx into xy#unpack and zip    cv2.rectangle(img, pt, (pt[0] + w, pt[1] + h), (0, 0, 255), 2)#(0, 0, 255) blueplt.imshow(img,cmap = "grey")# =============================================================================# res = cv2.matchTemplate(img_gray, template_img, cv2.TM_SQDIFF)# #methods available: ['cv2.TM_CCOEFF', 'cv2.TM_CCOEFF_NORMED', 'cv2.TM_CCORR',# #            'cv2.TM_CCORR_NORMED', 'cv2.TM_SQDIFF', 'cv2.TM_SQDIFF_NORMED']## plt.imshow(res, cmap = "grey")#probability map of matching## min_val,max_val,min_loc, max_loc = cv2.minMaxLoc(res)## top_left = min_loc# bottom_right = (top_left[0]+w, top_left[1]+h)# cv2.rectangle(img_gray, top_left, bottom_right, 255,2)# #255 white, 2 thickness# plt.imshow(img_gray,cmap="gray")# =============================================================================